+/// DEC cursor save: `ESC 7` (DECSC)
+pub const CURSOR_SAVE: &[u8] = b"\x1b7";
+
+/// DEC cursor restore: `ESC 8` (DECRC)
+pub const CURSOR_RESTORE: &[u8] = b"\x1b8";
